defmodule MyAppWeb.URLController do
  use MyAppWeb, :controller

  def fetch(conn, %{"url" => url}) do
    case HTTPoison.get(url) do
      {:ok, response} ->
        conn
        |> put_status(:ok)
        |> json(%{data: response.body})

      {:error, error} ->
        conn
        |> put_status(:internal_server_error)
        |> json(%{message: "Error fetching URL: #{inspect(error)}"})
    end
  end
end